// Parse LLM response and compare to threshold
const llmResponse = $input.item.json.response || $input.item.json;
let parsed;
try {
  parsed = JSON.parse(llmResponse);
} catch(e) {
  // Try to extract JSON from response
  const match = llmResponse.match(/\{[^}]+\}/);
  parsed = match ? JSON.parse(match[0]) : { price: null, found: false };
}

const threshold = $input.item.json.threshold || 999;
const isDeal = parsed.found && parsed.price !== null && parsed.price < threshold;

return {
  product: $input.item.json.name || 'Unknown',
  asin: $input.item.json.asin,
  price: parsed.price,
  threshold: threshold,
  isDeal: isDeal,
  found: parsed.found
};

