parameters.jsCode:
// Log all prices for record-keeping
const items = $input.all();
const summary = items.map(item => ({
  product: item.json.product,
  price: item.json.price,
  threshold: item.json.threshold,
  isDeal: item.json.isDeal,
  found: item.json.found
}));

return {
  timestamp: new Date().toISOString(),
  checked: summary,
  deals: summary.filter(s => s.isDeal)
};
